import { useEffect, useMemo, useState } from "react";
import api from "../api/axiosConfig";

const sections = [
  { id: "users", label: "Users" },
  { id: "bookings", label: "Booking" },
  { id: "maintenance", label: "Maintenance" },
  { id: "assets", label: "Assets" },
];

function AdminDashboard({ user }) {
  const [dashboard, setDashboard] = useState(null);
  const [activeSection, setActiveSection] = useState("users");
  const [loading, setLoading] = useState(true);
  const [savingId, setSavingId] = useState(null);
  const [error, setError] = useState("");

  const [assetItems, setAssetItems] = useState([]);
  const [assetLoading, setAssetLoading] = useState(false);
  const [assetError, setAssetError] = useState("");
  const [assetFilters, setAssetFilters] = useState({
    q: "",
    type: "",
    minCapacity: "",
    location: "",
    status: "",
  });
  const [assetForm, setAssetForm] = useState({
    id: null,
    name: "",
    type: "",
    capacity: "",
    location: "",
    status: "ACTIVE",
    availabilityWindows: [],
  });
  const [assetFormErrors, setAssetFormErrors] = useState({});
  const [assetFilterErrors, setAssetFilterErrors] = useState({});
  const [assetSaving, setAssetSaving] = useState(false);

  const loadDashboard = async () => {
    setLoading(true);
    setError("");

    try {
      const response = await api.get("/admin/dashboard");
      if (response.data?.success) {
        setDashboard(response.data.data);
      } else {
        setError(response.data?.message || "Unable to load admin dashboard.");
      }
    } catch (err) {
      setError(
        err.response?.data?.message || "Unable to load admin dashboard.",
      );
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadDashboard();
  }, []);

  const toBackendDateTime = (value) => {
    if (!value) return null;
    if (value.length === 16) return `${value}:00`;
    return value;
  };

  const toDatetimeLocal = (value) => {
    if (!value) return "";
    return value.length >= 16 ? value.slice(0, 16) : value;
  };

  const allowedAssetStatuses = new Set(["ACTIVE", "OUT_OF_SERVICE"]);

  const sanitizeText = (value, maxLen) => {
    const text = String(value ?? "").replace(/[\r\n]+/g, " ").trim();
    return text.length > maxLen ? text.slice(0, maxLen) : text;
  };

  const validateAssetFilters = (nextFilters) => {
    const errors = {};
    const sanitized = {
      ...nextFilters,
      q: sanitizeText(nextFilters.q, 80),
      type: sanitizeText(nextFilters.type, 40),
      location: sanitizeText(nextFilters.location, 60),
      status: nextFilters.status ?? "",
      minCapacity: nextFilters.minCapacity ?? "",
    };

    if (sanitized.minCapacity !== "") {
      const asNumber = Number(sanitized.minCapacity);
      const isInteger = Number.isInteger(asNumber);
      if (!Number.isFinite(asNumber) || !isInteger || asNumber < 0) {
        errors.minCapacity = "Minimum capacity must be a non-negative whole number.";
      }
    }

    if (sanitized.status && !allowedAssetStatuses.has(sanitized.status)) {
      errors.status = "Status must be ACTIVE or OUT_OF_SERVICE.";
    }

    return { sanitized, errors, isValid: Object.keys(errors).length === 0 };
  };

  const normalizeDatetimeForCompare = (value) => {
    const trimmed = String(value ?? "").trim();
    if (!trimmed) return "";
    if (trimmed.length === 16) return `${trimmed}:00`;
    if (trimmed.length >= 19) return trimmed.slice(0, 19);
    return trimmed;
  };

  const validateAssetForm = (nextForm) => {
    const errors = {};

    const sanitized = {
      ...nextForm,
      name: sanitizeText(nextForm.name, 80),
      type: sanitizeText(nextForm.type, 40),
      location: sanitizeText(nextForm.location, 60),
      status: nextForm.status ?? "ACTIVE",
      capacity: String(nextForm.capacity ?? "").trim(),
      availabilityWindows: (nextForm.availabilityWindows || []).map((w) => ({
        startAt: String(w?.startAt ?? "").trim(),
        endAt: String(w?.endAt ?? "").trim(),
      })),
    };

    if (!sanitized.name) errors.name = "Name is required.";
    if (!sanitized.type) errors.type = "Type is required.";
    if (!sanitized.location) errors.location = "Location is required.";

    if (!allowedAssetStatuses.has(sanitized.status)) {
      errors.status = "Status must be ACTIVE or OUT_OF_SERVICE.";
    }

    if (sanitized.capacity === "") {
      errors.capacity = "Capacity is required.";
    } else {
      const asNumber = Number(sanitized.capacity);
      const isInteger = Number.isInteger(asNumber);
      if (!Number.isFinite(asNumber) || !isInteger || asNumber < 0) {
        errors.capacity = "Capacity must be a non-negative whole number.";
      }
    }

    if (sanitized.availabilityWindows.length > 20) {
      errors.availabilityWindows = "A maximum of 20 availability windows is allowed.";
    }

    const filledWindows = [];
    sanitized.availabilityWindows.forEach((w, idx) => {
      const startAt = w.startAt;
      const endAt = w.endAt;

      if (!startAt && !endAt) return;

      if (!startAt) {
        errors[`availabilityWindows.${idx}.startAt`] = "Start time is required.";
        return;
      }
      if (!endAt) {
        errors[`availabilityWindows.${idx}.endAt`] = "End time is required.";
        return;
      }

      if (startAt.length < 16) {
        errors[`availabilityWindows.${idx}.startAt`] = "Start time is invalid.";
        return;
      }
      if (endAt.length < 16) {
        errors[`availabilityWindows.${idx}.endAt`] = "End time is invalid.";
        return;
      }

      const startKey = normalizeDatetimeForCompare(startAt);
      const endKey = normalizeDatetimeForCompare(endAt);
      if (startKey >= endKey) {
        errors[`availabilityWindows.${idx}.range`] = "Start must be before end.";
        return;
      }

      filledWindows.push({ idx, startKey, endKey });
    });

    const sorted = [...filledWindows].sort((a, b) => a.startKey.localeCompare(b.startKey));
    for (let i = 1; i < sorted.length; i += 1) {
      const prev = sorted[i - 1];
      const curr = sorted[i];
      if (curr.startKey < prev.endKey) {
        errors[`availabilityWindows.${curr.idx}.range`] = "This window overlaps with another window.";
      }
    }

    return { sanitized, errors, isValid: Object.keys(errors).length === 0 };
  };

  const loadAssets = async (nextFilters = assetFilters) => {
    setAssetLoading(true);
    setAssetError("");
    try {
      const params = {
        q: nextFilters.q || undefined,
        type: nextFilters.type || undefined,
        minCapacity:
          nextFilters.minCapacity === "" ? undefined : nextFilters.minCapacity,
        location: nextFilters.location || undefined,
        status: nextFilters.status || undefined,
      };
      const response = await api.get("/admin/assets", { params });
      if (response.data?.success) {
        setAssetItems(response.data.data || []);
      } else {
        setAssetError(response.data?.message || "Unable to load assets.");
      }
    } catch (err) {
      setAssetError(err.response?.data?.message || "Unable to load assets.");
    } finally {
      setAssetLoading(false);
    }
  };

  useEffect(() => {
    if (activeSection === "assets") {
      loadAssets();
    }
  }, [activeSection]);

  const resetAssetForm = () => {
    setAssetForm({
      id: null,
      name: "",
      type: "",
      capacity: "",
      location: "",
      status: "ACTIVE",
      availabilityWindows: [],
    });
    setAssetFormErrors({});
  };

  const startEditAsset = (asset) => {
    setAssetError("");
    setAssetFormErrors({});
    setAssetForm({
      id: asset.id,
      name: asset.name || "",
      type: asset.type || "",
      capacity: asset.capacity ?? "",
      location: asset.location || "",
      status: asset.status || "ACTIVE",
      availabilityWindows: (asset.availabilityWindows || []).map((w) => ({
        startAt: toDatetimeLocal(w.startAt),
        endAt: toDatetimeLocal(w.endAt),
      })),
    });
  };

  const submitAssetForm = async (e) => {
    e.preventDefault();
    setAssetError("");

    const { sanitized, errors, isValid } = validateAssetForm(assetForm);
    setAssetForm((prev) => ({ ...prev, ...sanitized }));
    setAssetFormErrors(errors);
    if (!isValid) return;

    setAssetSaving(true);

    const payload = {
      name: sanitized.name,
      type: sanitized.type,
      capacity: Number(sanitized.capacity),
      location: sanitized.location,
      status: sanitized.status,
      availabilityWindows: sanitized.availabilityWindows
        .filter((w) => w.startAt && w.endAt)
        .map((w) => ({
          startAt: toBackendDateTime(w.startAt),
          endAt: toBackendDateTime(w.endAt),
        })),
    };

    try {
      if (assetForm.id) {
        await api.put(`/admin/assets/${assetForm.id}`, payload);
      } else {
        await api.post("/admin/assets", payload);
      }
      await loadAssets();
      await loadDashboard();
      resetAssetForm();
    } catch (err) {
      setAssetError(err.response?.data?.message || "Unable to save asset.");
    } finally {
      setAssetSaving(false);
    }
  };

  const deleteAsset = async (asset) => {
    setAssetError("");
    setAssetSaving(true);
    try {
      await api.delete(`/admin/assets/${asset.id}`);
      await loadAssets();
      await loadDashboard();
      if (assetForm.id === asset.id) {
        resetAssetForm();
      }
    } catch (err) {
      setAssetError(err.response?.data?.message || "Unable to delete asset.");
    } finally {
      setAssetSaving(false);
    }
  };

  const users = dashboard?.users || [];
  const roleStats = dashboard?.roleStats || [];
  const loginChart = dashboard?.loginChart || [];
  const maxLogins = useMemo(
    () => Math.max(1, ...loginChart.map((item) => item.loginCount || 0)),
    [loginChart],
  );

  const updateUserRole = async (userId, role) => {
    setSavingId(userId);
    try {
      await api.put(`/admin/users/${userId}/role`, { role });
      await loadDashboard();
    } catch (err) {
      setError(err.response?.data?.message || "Unable to update user role.");
    } finally {
      setSavingId(null);
    }
  };

  const toggleBlock = async (targetUser) => {
    setSavingId(targetUser.id);
    try {
      await api.put(`/admin/users/${targetUser.id}/block`, {
        blocked: !targetUser.blocked,
      });
      await loadDashboard();
    } catch (err) {
      setError(err.response?.data?.message || "Unable to update user status.");
    } finally {
      setSavingId(null);
    }
  };

  const moduleCards = [
    {
      title: "Users",
      value: dashboard?.totalUsers ?? 0,
      note: `${dashboard?.blockedUsers ?? 0} blocked accounts`,
    },
    {
      title: "Booking",
      value: dashboard?.bookingCount ?? 0,
      note: "Reservation records loaded",
    },
    {
      title: "Maintenance",
      value: dashboard?.maintenanceCount ?? 0,
      note: "Service requests tracked",
    },
    {
      title: "Assets",
      value: dashboard?.assetCount ?? 0,
      note: "Asset inventory overview",
    },
  ];

  return (
    <main className="relative overflow-hidden">
      <div className="pointer-events-none absolute inset-0 bg-[radial-gradient(circle_at_top_left,_rgba(34,211,238,0.16),_transparent_30%),radial-gradient(circle_at_bottom_right,_rgba(14,165,233,0.14),_transparent_35%)]" />

      <section className="relative mx-auto flex max-w-7xl gap-6 px-4 py-6 sm:px-6 lg:px-8">
        <aside className="hidden w-72 shrink-0 lg:block">
          <div className="sticky top-24 rounded-3xl border border-slate-800 bg-slate-900/80 p-5 shadow-2xl shadow-cyan-950/20 backdrop-blur">
            <p className="text-xs font-semibold uppercase tracking-[0.3em] text-cyan-400">
              Admin Console
            </p>
            <h2 className="mt-2 text-2xl font-black text-white">UniOps</h2>
            <p className="mt-2 text-sm text-slate-300">{user?.name}</p>
            <div className="mt-6 space-y-2">
              {sections.map((section) => (
                <button
                  key={section.id}
                  type="button"
                  onClick={() => setActiveSection(section.id)}
                  className={`flex w-full items-center justify-between rounded-2xl px-4 py-3 text-left text-sm font-semibold transition ${
                    activeSection === section.id
                      ? "bg-cyan-500 text-slate-950"
                      : "bg-slate-950/60 text-slate-200 hover:bg-slate-800"
                  }`}
                >
                  <span>{section.label}</span>
                  <span className="text-xs opacity-80">
                    {section.id === activeSection ? "Open" : "View"}
                  </span>
                </button>
              ))}
            </div>

            <div className="mt-6 rounded-2xl border border-cyan-500/20 bg-cyan-500/10 p-4 text-sm text-cyan-100">
              Signed in as {user?.role}. Role control and block/unblock actions
              are available on the Users panel.
            </div>
          </div>
        </aside>

        <div className="min-w-0 flex-1 space-y-6">
          <div className="rounded-3xl border border-slate-800 bg-slate-900/80 p-6 shadow-2xl shadow-cyan-950/10 backdrop-blur">
            <p className="text-xs font-semibold uppercase tracking-[0.3em] text-cyan-400">
              Admin Dashboard
            </p>
            <div className="mt-3 flex flex-col gap-3 sm:flex-row sm:items-end sm:justify-between">
              <div>
                <h1 className="text-3xl font-black text-white sm:text-4xl">
                  Control users, bookings, maintenance, and assets.
                </h1>
                <p className="mt-2 max-w-2xl text-sm text-slate-300 sm:text-base">
                  Review role distribution, watch login activity, and manage
                  user access from one place.
                </p>
              </div>
              <button
                type="button"
                onClick={loadDashboard}
                className="rounded-xl bg-cyan-500 px-4 py-2 text-sm font-semibold text-slate-950 transition hover:bg-cyan-400"
              >
                Refresh data
              </button>
            </div>
          </div>

          {error && (
            <div className="rounded-2xl border border-rose-500/30 bg-rose-500/10 px-4 py-3 text-sm text-rose-200">
              {error}
            </div>
          )}

          <div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4">
            <StatCard
              label="Total users"
              value={dashboard?.totalUsers ?? 0}
              tone="cyan"
            />
            <StatCard
              label="Admins"
              value={dashboard?.adminUsers ?? 0}
              tone="blue"
            />
            <StatCard
              label="Students"
              value={dashboard?.studentUsers ?? 0}
              tone="emerald"
            />
            <StatCard
              label="Blocked"
              value={dashboard?.blockedUsers ?? 0}
              tone="rose"
            />
          </div>

          <div className="grid gap-6 xl:grid-cols-[1.6fr_1fr]">
            <section className="rounded-3xl border border-slate-800 bg-slate-900/80 p-6 shadow-xl shadow-cyan-950/10">
              <div className="flex items-center justify-between gap-4">
                <div>
                  <h2 className="text-xl font-bold text-white">
                    Users overview
                  </h2>
                  <p className="mt-1 text-sm text-slate-300">
                    Role split and login activity based on current user records.
                  </p>
                </div>
                <span className="rounded-full border border-cyan-400/30 bg-cyan-500/10 px-3 py-1 text-xs font-semibold uppercase tracking-[0.2em] text-cyan-300">
                  {dashboard?.totalLogins ?? 0} total logins
                </span>
              </div>

              <div className="mt-6 grid gap-4 md:grid-cols-2">
                <div className="rounded-2xl border border-slate-800 bg-slate-950/60 p-4">
                  <h3 className="text-sm font-semibold uppercase tracking-[0.2em] text-slate-400">
                    Role percentage
                  </h3>
                  <div className="mt-4 space-y-4">
                    {roleStats.map((item) => (
                      <div key={item.role}>
                        <div className="flex items-center justify-between text-sm text-slate-200">
                          <span>{item.role}</span>
                          <span>{item.percentage}%</span>
                        </div>
                        <div className="mt-2 h-3 rounded-full bg-slate-800">
                          <div
                            className="h-3 rounded-full bg-gradient-to-r from-cyan-400 to-blue-500"
                            style={{ width: `${item.percentage}%` }}
                          />
                        </div>
                        <p className="mt-1 text-xs text-slate-400">
                          {item.count} accounts
                        </p>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="rounded-2xl border border-slate-800 bg-slate-950/60 p-4">
                  <h3 className="text-sm font-semibold uppercase tracking-[0.2em] text-slate-400">
                    User logins
                  </h3>
                  <div className="mt-4 space-y-3">
                    {loginChart.map((item) => (
                      <div key={item.id}>
                        <div className="flex items-center justify-between gap-3 text-sm text-slate-200">
                          <span className="truncate">{item.name}</span>
                          <span>{item.loginCount}</span>
                        </div>
                        <div className="mt-2 h-3 rounded-full bg-slate-800">
                          <div
                            className="h-3 rounded-full bg-gradient-to-r from-emerald-400 to-cyan-400"
                            style={{
                              width: `${(item.loginCount / maxLogins) * 100}%`,
                            }}
                          />
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              <div className="mt-6 grid gap-4 sm:grid-cols-3">
                {moduleCards.map((card) => (
                  <div
                    key={card.title}
                    className="rounded-2xl border border-slate-800 bg-slate-950/60 p-4"
                  >
                    <p className="text-xs font-semibold uppercase tracking-[0.2em] text-slate-400">
                      {card.title}
                    </p>
                    <p className="mt-3 text-3xl font-black text-white">
                      {card.value}
                    </p>
                    <p className="mt-2 text-sm text-slate-300">{card.note}</p>
                  </div>
                ))}
              </div>
            </section>

            <aside className="space-y-6">
              <section className="rounded-3xl border border-slate-800 bg-slate-900/80 p-6 shadow-xl shadow-cyan-950/10">
                <h2 className="text-xl font-bold text-white">Module panel</h2>
                <p className="mt-1 text-sm text-slate-300">
                  {activeSection === "users" &&
                    "Manage role changes, block status, and account activity."}
                  {activeSection === "bookings" &&
                    "View booking totals and reservation workload."}
                  {activeSection === "maintenance" &&
                    "Track open, active, and resolved maintenance requests."}
                  {activeSection === "assets" &&
                    "Monitor inventory and asset availability."}
                </p>

                <div className="mt-4 space-y-3 text-sm text-slate-200">
                  <InfoRow
                    label="Bookings"
                    value={dashboard?.bookingCount ?? 0}
                  />
                  <InfoRow
                    label="Maintenance"
                    value={dashboard?.maintenanceCount ?? 0}
                  />
                  <InfoRow label="Assets" value={dashboard?.assetCount ?? 0} />
                  <InfoRow
                    label="Blocked users"
                    value={dashboard?.blockedUsers ?? 0}
                  />
                </div>
              </section>

              <section className="rounded-3xl border border-slate-800 bg-slate-900/80 p-6 shadow-xl shadow-cyan-950/10">
                <h2 className="text-xl font-bold text-white">Current admin</h2>
                <p className="mt-2 text-sm text-slate-300">{user?.name}</p>
                <p className="text-sm text-cyan-300">{user?.email}</p>
                <div className="mt-4 rounded-2xl border border-cyan-500/20 bg-cyan-500/10 p-4 text-sm text-cyan-100">
                  Use the user table to promote students to admin, demote admins
                  to student, or block access.
                </div>
              </section>
            </aside>
          </div>

          {activeSection === "users" && (
            <section className="rounded-3xl border border-slate-800 bg-slate-900/80 p-6 shadow-xl shadow-cyan-950/10">
              <div className="flex flex-col gap-2 sm:flex-row sm:items-end sm:justify-between">
                <div>
                  <h2 className="text-xl font-bold text-white">
                    User management
                  </h2>
                  <p className="mt-1 text-sm text-slate-300">
                    Edit roles and toggle access without leaving the dashboard.
                  </p>
                </div>
                <span className="text-sm text-slate-400">
                  {users.length} users in total
                </span>
              </div>

              <div className="mt-4 overflow-x-auto">
                <table className="min-w-full border-separate border-spacing-y-3">
                  <thead>
                    <tr className="text-left text-xs uppercase tracking-[0.2em] text-slate-400">
                      <th className="px-4 py-2">User</th>
                      <th className="px-4 py-2">Role</th>
                      <th className="px-4 py-2">Logins</th>
                      <th className="px-4 py-2">Status</th>
                      <th className="px-4 py-2">Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {loading ? (
                      <tr>
                        <td
                          colSpan="5"
                          className="px-4 py-8 text-center text-slate-300"
                        >
                          Loading users...
                        </td>
                      </tr>
                    ) : (
                      users.map((item) => (
                        <tr
                          key={item.id}
                          className="rounded-2xl bg-slate-950/60"
                        >
                          <td className="rounded-l-2xl px-4 py-4">
                            <p className="font-semibold text-white">
                              {item.name}
                            </p>
                            <p className="text-sm text-slate-400">
                              {item.email}
                            </p>
                          </td>
                          <td className="px-4 py-4">
                            <select
                              value={item.role}
                              onChange={(e) =>
                                updateUserRole(item.id, e.target.value)
                              }
                              disabled={savingId === item.id}
                              className="rounded-lg border border-slate-700 bg-slate-950 px-3 py-2 text-sm text-slate-100 outline-none transition focus:border-cyan-400"
                            >
                              <option value="STUDENT">STUDENT</option>
                              <option value="ADMIN">ADMIN</option>
                            </select>
                          </td>
                          <td className="px-4 py-4 text-sm text-slate-200">
                            {item.loginCount}
                          </td>
                          <td className="px-4 py-4">
                            <span
                              className={`rounded-full px-3 py-1 text-xs font-semibold uppercase tracking-[0.2em] ${
                                item.blocked
                                  ? "bg-rose-500/20 text-rose-300"
                                  : "bg-emerald-500/20 text-emerald-300"
                              }`}
                            >
                              {item.blocked ? "Blocked" : "Active"}
                            </span>
                          </td>
                          <td className="rounded-r-2xl px-4 py-4">
                            <button
                              type="button"
                              onClick={() => toggleBlock(item)}
                              disabled={savingId === item.id}
                              className={`rounded-lg px-3 py-2 text-sm font-semibold transition disabled:cursor-not-allowed disabled:opacity-60 ${
                                item.blocked
                                  ? "bg-emerald-500 text-slate-950 hover:bg-emerald-400"
                                  : "bg-rose-500 text-white hover:bg-rose-400"
                              }`}
                            >
                              {item.blocked ? "Unblock" : "Block"}
                            </button>
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
              </div>
            </section>
          )}

          {activeSection === "assets" && (
            <section className="rounded-3xl border border-slate-800 bg-slate-900/80 p-6 shadow-xl shadow-cyan-950/10">
              <div className="flex flex-col gap-2 sm:flex-row sm:items-end sm:justify-between">
                <div>
                  <h2 className="text-xl font-bold text-white">
                    Resource catalogue management
                  </h2>
                  <p className="mt-1 text-sm text-slate-300">
                    Add, edit, delete resources and set status/availability.
                  </p>
                </div>
                <button
                  type="button"
                  onClick={() => loadAssets()}
                  className="rounded-xl bg-cyan-500 px-4 py-2 text-sm font-semibold text-slate-950 transition hover:bg-cyan-400"
                >
                  Refresh assets
                </button>
              </div>

              {assetError && (
                <div className="mt-4 rounded-2xl border border-rose-500/30 bg-rose-500/10 px-4 py-3 text-sm text-rose-200">
                  {assetError}
                </div>
              )}

              <form
                onSubmit={submitAssetForm}
                className="mt-6 rounded-2xl border border-slate-800 bg-slate-950/50 p-5"
              >
                <div className="flex flex-col gap-2 sm:flex-row sm:items-end sm:justify-between">
                  <div>
                    <h3 className="text-sm font-semibold uppercase tracking-[0.2em] text-slate-400">
                      {assetForm.id ? `Edit resource #${assetForm.id}` : "Add new resource"}
                    </h3>
                    <p className="mt-1 text-sm text-slate-300">
                      Required metadata: type, capacity, location, status.
                    </p>
                  </div>
                  {assetForm.id && (
                    <button
                      type="button"
                      onClick={resetAssetForm}
                      className="rounded-xl border border-slate-700 bg-slate-900 px-4 py-2 text-sm font-semibold text-slate-200 transition hover:bg-slate-800"
                    >
                      Cancel edit
                    </button>
                  )}
                </div>

                <div className="mt-4 grid gap-4 md:grid-cols-2 xl:grid-cols-3">
                  <div>
                    <label className="mb-1 block text-sm font-medium text-slate-200">
                      Name
                    </label>
                    <input
                      value={assetForm.name}
                      onChange={(e) => {
                        setAssetForm((prev) => ({ ...prev, name: e.target.value }));
                        if (assetFormErrors.name) {
                          setAssetFormErrors((prev) => ({ ...prev, name: undefined }));
                        }
                      }}
                      onBlur={() => {
                        if (assetFormErrors.name) {
                          setAssetForm((prev) => ({
                            ...prev,
                            name: sanitizeText(prev.name, 80),
                          }));
                        }
                      }}
                      className={`w-full rounded-lg border bg-slate-950 px-3 py-2 text-sm text-slate-100 outline-none transition focus:border-cyan-400 ${
                        assetFormErrors.name ? "border-rose-500/60" : "border-slate-700"
                      }`}
                      placeholder="Lecture Hall A"
                      required
                    />
                    {assetFormErrors.name && (
                      <p className="mt-2 text-sm text-rose-200">{assetFormErrors.name}</p>
                    )}
                  </div>

                  <div>
                    <label className="mb-1 block text-sm font-medium text-slate-200">
                      Type
                    </label>
                    <input
                      value={assetForm.type}
                      onChange={(e) => {
                        setAssetForm((prev) => ({ ...prev, type: e.target.value }));
                        if (assetFormErrors.type) {
                          setAssetFormErrors((prev) => ({ ...prev, type: undefined }));
                        }
                      }}
                      onBlur={() => {
                        if (assetFormErrors.type) {
                          setAssetForm((prev) => ({
                            ...prev,
                            type: sanitizeText(prev.type, 40),
                          }));
                        }
                      }}
                      className={`w-full rounded-lg border bg-slate-950 px-3 py-2 text-sm text-slate-100 outline-none transition focus:border-cyan-400 ${
                        assetFormErrors.type ? "border-rose-500/60" : "border-slate-700"
                      }`}
                      placeholder="LECTURE_HALL / LAB / MEETING_ROOM / EQUIPMENT"
                      required
                    />
                    {assetFormErrors.type && (
                      <p className="mt-2 text-sm text-rose-200">{assetFormErrors.type}</p>
                    )}
                  </div>

                  <div>
                    <label className="mb-1 block text-sm font-medium text-slate-200">
                      Capacity
                    </label>
                    <input
                      type="number"
                      min="0"
                      value={assetForm.capacity}
                      onChange={(e) => {
                        setAssetForm((prev) => ({
                          ...prev,
                          capacity: e.target.value,
                        }));
                        if (assetFormErrors.capacity) {
                          setAssetFormErrors((prev) => ({
                            ...prev,
                            capacity: undefined,
                          }));
                        }
                      }}
                      className={`w-full rounded-lg border bg-slate-950 px-3 py-2 text-sm text-slate-100 outline-none transition focus:border-cyan-400 ${
                        assetFormErrors.capacity ? "border-rose-500/60" : "border-slate-700"
                      }`}
                      placeholder="0"
                      required
                    />
                    {assetFormErrors.capacity && (
                      <p className="mt-2 text-sm text-rose-200">
                        {assetFormErrors.capacity}
                      </p>
                    )}
                  </div>

                  <div className="md:col-span-2">
                    <label className="mb-1 block text-sm font-medium text-slate-200">
                      Location
                    </label>
                    <input
                      value={assetForm.location}
                      onChange={(e) => {
                        setAssetForm((prev) => ({
                          ...prev,
                          location: e.target.value,
                        }));
                        if (assetFormErrors.location) {
                          setAssetFormErrors((prev) => ({
                            ...prev,
                            location: undefined,
                          }));
                        }
                      }}
                      onBlur={() => {
                        if (assetFormErrors.location) {
                          setAssetForm((prev) => ({
                            ...prev,
                            location: sanitizeText(prev.location, 60),
                          }));
                        }
                      }}
                      className={`w-full rounded-lg border bg-slate-950 px-3 py-2 text-sm text-slate-100 outline-none transition focus:border-cyan-400 ${
                        assetFormErrors.location
                          ? "border-rose-500/60"
                          : "border-slate-700"
                      }`}
                      placeholder="Block A - Level 1"
                      required
                    />
                    {assetFormErrors.location && (
                      <p className="mt-2 text-sm text-rose-200">
                        {assetFormErrors.location}
                      </p>
                    )}
                  </div>

                  <div>
                    <label className="mb-1 block text-sm font-medium text-slate-200">
                      Status
                    </label>
                    <select
                      value={assetForm.status}
                      onChange={(e) => {
                        setAssetForm((prev) => ({
                          ...prev,
                          status: e.target.value,
                        }));
                        if (assetFormErrors.status) {
                          setAssetFormErrors((prev) => ({ ...prev, status: undefined }));
                        }
                      }}
                      className={`w-full rounded-lg border bg-slate-950 px-3 py-2 text-sm text-slate-100 outline-none transition focus:border-cyan-400 ${
                        assetFormErrors.status ? "border-rose-500/60" : "border-slate-700"
                      }`}
                    >
                      <option value="ACTIVE">ACTIVE</option>
                      <option value="OUT_OF_SERVICE">OUT_OF_SERVICE</option>
                    </select>
                    {assetFormErrors.status && (
                      <p className="mt-2 text-sm text-rose-200">
                        {assetFormErrors.status}
                      </p>
                    )}
                  </div>
                </div>

                <div className="mt-5">
                  <div className="flex items-center justify-between">
                    <h4 className="text-sm font-semibold uppercase tracking-[0.2em] text-slate-400">
                      Availability windows
                    </h4>
                    <button
                      type="button"
                      onClick={() =>
                        setAssetForm((prev) => ({
                          ...prev,
                          availabilityWindows: [
                            ...(prev.availabilityWindows || []),
                            { startAt: "", endAt: "" },
                          ],
                        }))
                      }
                      className="rounded-xl border border-slate-700 bg-slate-900 px-3 py-2 text-xs font-semibold text-slate-200 transition hover:bg-slate-800"
                    >
                      Add window
                    </button>
                  </div>

                  <div className="mt-3 space-y-3">
                    {assetFormErrors.availabilityWindows && (
                      <div className="rounded-2xl border border-rose-500/30 bg-rose-500/10 px-4 py-3 text-sm text-rose-200">
                        {assetFormErrors.availabilityWindows}
                      </div>
                    )}
                    {(assetForm.availabilityWindows || []).length === 0 ? (
                      <p className="text-sm text-slate-400">
                        No windows set. Resource is treated as always available
                        when ACTIVE.
                      </p>
                    ) : (
                      assetForm.availabilityWindows.map((w, idx) => (
                        <div
                          key={idx}
                          className="grid gap-3 rounded-2xl border border-slate-800 bg-slate-950/60 p-4 md:grid-cols-[1fr_1fr_auto]"
                        >
                          <div>
                            <label className="mb-1 block text-xs font-semibold uppercase tracking-[0.2em] text-slate-400">
                              Start
                            </label>
                            <input
                              type="datetime-local"
                              value={w.startAt}
                              onChange={(e) => {
                                setAssetForm((prev) => {
                                  const next = [...prev.availabilityWindows];
                                  next[idx] = { ...next[idx], startAt: e.target.value };
                                  return { ...prev, availabilityWindows: next };
                                });

                                const startKey = `availabilityWindows.${idx}.startAt`;
                                const rangeKey = `availabilityWindows.${idx}.range`;
                                if (assetFormErrors[startKey] || assetFormErrors[rangeKey]) {
                                  setAssetFormErrors((prev) => ({
                                    ...prev,
                                    [startKey]: undefined,
                                    [rangeKey]: undefined,
                                  }));
                                }
                              }}
                              className={`w-full rounded-lg border bg-slate-950 px-3 py-2 text-sm text-slate-100 outline-none transition focus:border-cyan-400 ${
                                assetFormErrors[`availabilityWindows.${idx}.startAt`] ||
                                assetFormErrors[`availabilityWindows.${idx}.range`]
                                  ? "border-rose-500/60"
                                  : "border-slate-700"
                              }`}
                            />
                            {assetFormErrors[`availabilityWindows.${idx}.startAt`] && (
                              <p className="mt-2 text-sm text-rose-200">
                                {assetFormErrors[`availabilityWindows.${idx}.startAt`]}
                              </p>
                            )}
                          </div>
                          <div>
                            <label className="mb-1 block text-xs font-semibold uppercase tracking-[0.2em] text-slate-400">
                              End
                            </label>
                            <input
                              type="datetime-local"
                              value={w.endAt}
                              onChange={(e) => {
                                setAssetForm((prev) => {
                                  const next = [...prev.availabilityWindows];
                                  next[idx] = { ...next[idx], endAt: e.target.value };
                                  return { ...prev, availabilityWindows: next };
                                });

                                const endKey = `availabilityWindows.${idx}.endAt`;
                                const rangeKey = `availabilityWindows.${idx}.range`;
                                if (assetFormErrors[endKey] || assetFormErrors[rangeKey]) {
                                  setAssetFormErrors((prev) => ({
                                    ...prev,
                                    [endKey]: undefined,
                                    [rangeKey]: undefined,
                                  }));
                                }
                              }}
                              className={`w-full rounded-lg border bg-slate-950 px-3 py-2 text-sm text-slate-100 outline-none transition focus:border-cyan-400 ${
                                assetFormErrors[`availabilityWindows.${idx}.endAt`] ||
                                assetFormErrors[`availabilityWindows.${idx}.range`]
                                  ? "border-rose-500/60"
                                  : "border-slate-700"
                              }`}
                            />
                            {assetFormErrors[`availabilityWindows.${idx}.endAt`] && (
                              <p className="mt-2 text-sm text-rose-200">
                                {assetFormErrors[`availabilityWindows.${idx}.endAt`]}
                              </p>
                            )}
                          </div>
                          <div className="flex items-end">
                            <button
                              type="button"
                              onClick={() =>
                                setAssetForm((prev) => ({
                                  ...prev,
                                  availabilityWindows: prev.availabilityWindows.filter(
                                    (_, i) => i !== idx,
                                  ),
                                }))
                              }
                              className="rounded-lg bg-rose-500 px-3 py-2 text-sm font-semibold text-white transition hover:bg-rose-400"
                            >
                              Remove
                            </button>
                          </div>

                          {assetFormErrors[`availabilityWindows.${idx}.range`] && (
                            <p className="md:col-span-3 text-sm text-rose-200">
                              {assetFormErrors[`availabilityWindows.${idx}.range`]}
                            </p>
                          )}
                        </div>
                      ))
                    )}
                  </div>
                </div>

                <div className="mt-5 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-end">
                  <button
                    type="submit"
                    disabled={assetSaving}
                    className="rounded-xl bg-cyan-500 px-5 py-2 text-sm font-semibold text-slate-950 transition hover:bg-cyan-400 disabled:cursor-not-allowed disabled:opacity-70"
                  >
                    {assetSaving ? "Saving..." : assetForm.id ? "Save changes" : "Add resource"}
                  </button>
                </div>
              </form>

              <div className="mt-6 rounded-2xl border border-slate-800 bg-slate-950/50 p-5">
                <div className="flex flex-col gap-3 lg:flex-row lg:items-end lg:justify-between">
                  <div>
                    <h3 className="text-sm font-semibold uppercase tracking-[0.2em] text-slate-400">
                      Search and filter
                    </h3>
                    <p className="mt-1 text-sm text-slate-300">
                      Filter by type, capacity, location, and status.
                    </p>
                  </div>
                  <button
                    type="button"
                    onClick={() => {
                      const cleared = {
                        q: "",
                        type: "",
                        minCapacity: "",
                        location: "",
                        status: "",
                      };
                      setAssetFilters(cleared);
                      setAssetFilterErrors({});
                      loadAssets(cleared);
                    }}
                    className="rounded-xl border border-slate-700 bg-slate-900 px-4 py-2 text-sm font-semibold text-slate-200 transition hover:bg-slate-800"
                  >
                    Clear filters
                  </button>
                </div>

                <div className="mt-4 grid gap-4 md:grid-cols-2 xl:grid-cols-5">
                  <input
                    value={assetFilters.q}
                    onChange={(e) =>
                      setAssetFilters((prev) => ({ ...prev, q: e.target.value }))
                    }
                    className="w-full rounded-lg border border-slate-700 bg-slate-950 px-3 py-2 text-sm text-slate-100 outline-none transition focus:border-cyan-400"
                    placeholder="Search by name"
                  />
                  <input
                    value={assetFilters.type}
                    onChange={(e) =>
                      setAssetFilters((prev) => ({
                        ...prev,
                        type: e.target.value,
                      }))
                    }
                    className="w-full rounded-lg border border-slate-700 bg-slate-950 px-3 py-2 text-sm text-slate-100 outline-none transition focus:border-cyan-400"
                    placeholder="Type"
                  />
                  <input
                    type="number"
                    min="0"
                    value={assetFilters.minCapacity}
                    onChange={(e) => {
                      setAssetFilters((prev) => ({
                        ...prev,
                        minCapacity: e.target.value,
                      }));
                      if (assetFilterErrors.minCapacity) {
                        setAssetFilterErrors((prev) => ({
                          ...prev,
                          minCapacity: undefined,
                        }));
                      }
                    }}
                    className={`w-full rounded-lg border bg-slate-950 px-3 py-2 text-sm text-slate-100 outline-none transition focus:border-cyan-400 ${
                      assetFilterErrors.minCapacity
                        ? "border-rose-500/60"
                        : "border-slate-700"
                    }`}
                    placeholder="Min capacity"
                  />
                  <input
                    value={assetFilters.location}
                    onChange={(e) =>
                      setAssetFilters((prev) => ({
                        ...prev,
                        location: e.target.value,
                      }))
                    }
                    className="w-full rounded-lg border border-slate-700 bg-slate-950 px-3 py-2 text-sm text-slate-100 outline-none transition focus:border-cyan-400"
                    placeholder="Location"
                  />
                  <select
                    value={assetFilters.status}
                    onChange={(e) =>
                      setAssetFilters((prev) => ({
                        ...prev,
                        status: e.target.value,
                      }))
                    }
                    className={`w-full rounded-lg border bg-slate-950 px-3 py-2 text-sm text-slate-100 outline-none transition focus:border-cyan-400 ${
                      assetFilterErrors.status
                        ? "border-rose-500/60"
                        : "border-slate-700"
                    }`}
                  >
                    <option value="">Any status</option>
                    <option value="ACTIVE">ACTIVE</option>
                    <option value="OUT_OF_SERVICE">OUT_OF_SERVICE</option>
                  </select>
                </div>

                {(assetFilterErrors.minCapacity || assetFilterErrors.status) && (
                  <p className="mt-3 text-sm text-rose-200">
                    {assetFilterErrors.minCapacity || assetFilterErrors.status}
                  </p>
                )}

                <div className="mt-4 flex justify-end">
                  <button
                    type="button"
                    onClick={() => {
                      const { sanitized, errors, isValid } = validateAssetFilters(assetFilters);
                      setAssetFilters((prev) => ({ ...prev, ...sanitized }));
                      setAssetFilterErrors(errors);
                      if (!isValid) return;
                      loadAssets(sanitized);
                    }}
                    className="rounded-xl bg-cyan-500 px-4 py-2 text-sm font-semibold text-slate-950 transition hover:bg-cyan-400"
                  >
                    Search
                  </button>
                </div>
              </div>

              <div className="mt-6 overflow-x-auto">
                <table className="min-w-full border-separate border-spacing-y-3">
                  <thead>
                    <tr className="text-left text-xs uppercase tracking-[0.2em] text-slate-400">
                      <th className="px-4 py-2">Resource</th>
                      <th className="px-4 py-2">Type</th>
                      <th className="px-4 py-2">Capacity</th>
                      <th className="px-4 py-2">Location</th>
                      <th className="px-4 py-2">Status</th>
                      <th className="px-4 py-2">Available</th>
                      <th className="px-4 py-2">Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {assetLoading ? (
                      <tr>
                        <td
                          colSpan="7"
                          className="px-4 py-8 text-center text-slate-300"
                        >
                          Loading assets...
                        </td>
                      </tr>
                    ) : assetItems.length === 0 ? (
                      <tr>
                        <td
                          colSpan="7"
                          className="px-4 py-8 text-center text-slate-300"
                        >
                          No resources found.
                        </td>
                      </tr>
                    ) : (
                      assetItems.map((asset) => (
                        <tr
                          key={asset.id}
                          className="rounded-2xl bg-slate-950/60"
                        >
                          <td className="rounded-l-2xl px-4 py-4">
                            <p className="font-semibold text-white">
                              {asset.name}
                            </p>
                            <p className="text-sm text-slate-400">
                              ID: {asset.id}
                            </p>
                          </td>
                          <td className="px-4 py-4 text-sm text-slate-200">
                            {asset.type}
                          </td>
                          <td className="px-4 py-4 text-sm text-slate-200">
                            {asset.capacity}
                          </td>
                          <td className="px-4 py-4 text-sm text-slate-200">
                            {asset.location}
                          </td>
                          <td className="px-4 py-4">
                            <span
                              className={`rounded-full px-3 py-1 text-xs font-semibold uppercase tracking-[0.2em] ${
                                asset.status === "ACTIVE"
                                  ? "bg-emerald-500/20 text-emerald-300"
                                  : "bg-rose-500/20 text-rose-300"
                              }`}
                            >
                              {asset.status}
                            </span>
                          </td>
                          <td className="px-4 py-4">
                            <span
                              className={`rounded-full px-3 py-1 text-xs font-semibold uppercase tracking-[0.2em] ${
                                asset.availableNow
                                  ? "bg-cyan-500/20 text-cyan-300"
                                  : "bg-slate-800 text-slate-200"
                              }`}
                            >
                              {asset.availableNow ? "Available" : "Not now"}
                            </span>
                          </td>
                          <td className="rounded-r-2xl px-4 py-4">
                            <div className="flex flex-wrap gap-2">
                              <button
                                type="button"
                                onClick={() => startEditAsset(asset)}
                                className="rounded-lg bg-slate-800 px-3 py-2 text-sm font-semibold text-slate-100 transition hover:bg-slate-700"
                              >
                                Edit
                              </button>
                              <button
                                type="button"
                                onClick={() => deleteAsset(asset)}
                                disabled={assetSaving}
                                className="rounded-lg bg-rose-500 px-3 py-2 text-sm font-semibold text-white transition hover:bg-rose-400 disabled:cursor-not-allowed disabled:opacity-70"
                              >
                                Delete
                              </button>
                            </div>
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
              </div>
            </section>
          )}

          {activeSection !== "users" && activeSection !== "assets" && (
            <section className="rounded-3xl border border-slate-800 bg-slate-900/80 p-6 shadow-xl shadow-cyan-950/10">
              <h2 className="text-xl font-bold text-white">
                {
                  sections.find((section) => section.id === activeSection)
                    ?.label
                }
              </h2>
              <p className="mt-2 text-sm text-slate-300">
                The sidebar is wired and the summary cards are live. Expand this
                module with CRUD actions when the domain workflow is ready.
              </p>
              <div className="mt-4 grid gap-4 sm:grid-cols-3">
                {moduleCards.map((card) => (
                  <div
                    key={card.title}
                    className="rounded-2xl border border-slate-800 bg-slate-950/60 p-4"
                  >
                    <p className="text-sm text-slate-400">{card.title}</p>
                    <p className="mt-2 text-2xl font-black text-white">
                      {card.value}
                    </p>
                  </div>
                ))}
              </div>
            </section>
          )}
        </div>
      </section>
    </main>
  );
}

function StatCard({ label, value, tone }) {
  const toneClasses = {
    cyan: "from-cyan-500/20 to-cyan-500/5 border-cyan-400/20 text-cyan-300",
    blue: "from-blue-500/20 to-blue-500/5 border-blue-400/20 text-blue-300",
    emerald:
      "from-emerald-500/20 to-emerald-500/5 border-emerald-400/20 text-emerald-300",
    rose: "from-rose-500/20 to-rose-500/5 border-rose-400/20 text-rose-300",
  };

  return (
    <div
      className={`rounded-3xl border bg-gradient-to-br p-5 shadow-lg ${toneClasses[tone]}`}
    >
      <p className="text-xs font-semibold uppercase tracking-[0.2em] text-slate-300">
        {label}
      </p>
      <p className="mt-3 text-4xl font-black text-white">{value}</p>
    </div>
  );
}

function InfoRow({ label, value }) {
  return (
    <div className="flex items-center justify-between rounded-2xl border border-slate-800 bg-slate-950/60 px-4 py-3">
      <span className="text-slate-300">{label}</span>
      <span className="font-semibold text-white">{value}</span>
    </div>
  );
}

export default AdminDashboard;
